# Triagem simplificada de candidatos
nome = input("Nome do candidato: ")
idade = int(input("Idade: "))
experiencia_anos = int(input("Anos de experiência: "))

if idade >= 18 and experiencia_anos >= 2:
    print(f"{nome}: APROVADO na triagem")
else:
    print(f"{nome}: REPROVADO na triagem")
    if idade < 18:
        print("Motivo: idade mínima não atingida (18 anos)")
    if experiencia_anos < 2:
        print("Motivo: experiência insuficiente (mínimo 2 anos)")
